// src/chains/const/chainIds.ts
var ALL_SUPPORTED_CHAINS_MAP = {
  [SupportedChainId.MAINNET]: mainnet,
  [SupportedChainId.GNOSIS_CHAIN]: gnosisChain,
  [SupportedChainId.ARBITRUM_ONE]: arbitrumOne,
  [SupportedChainId.BASE]: base,
  [SupportedChainId.AVALANCHE]: avalanche,
  [SupportedChainId.POLYGON]: polygon,
  [SupportedChainId.BNB]: bnb,
  [SupportedChainId.PLASMA]: plasma,
  [SupportedChainId.LINEA]: linea,
  [SupportedChainId.INK]: ink,
  [SupportedChainId.SEPOLIA]: sepolia
};
var ALL_SUPPORTED_CHAINS = Object.values(ALL_SUPPORTED_CHAINS_MAP);
var ALL_SUPPORTED_CHAIN_IDS = ALL_SUPPORTED_CHAINS.map(
  (chain) => chain.id
);
var TRADABLE_SUPPORTED_CHAINS = Object.values(ALL_SUPPORTED_CHAINS_MAP).filter(
  (chain) => !chain.isDeprecated
);
var TRADABLE_SUPPORTED_CHAIN_IDS = TRADABLE_SUPPORTED_CHAINS.map(
  (chain) => chain.id
);
var ADDITIONAL_TARGET_CHAINS_MAP = {
  [AdditionalTargetChainId.OPTIMISM]: optimism,
  [AdditionalTargetChainId.BITCOIN]: bitcoin,
  [AdditionalTargetChainId.SOLANA]: solana
};
var ALL_ADDITIONAL_TARGET_CHAINS = Object.values(ADDITIONAL_TARGET_CHAINS_MAP);
var ALL_ADDITIONAL_TARGET_CHAIN_IDS = ALL_ADDITIONAL_TARGET_CHAINS.map(
  (chain) => chain.id
);
var ALL_CHAINS = ALL_SUPPORTED_CHAINS.concat(ALL_ADDITIONAL_TARGET_CHAINS);
var ALL_CHAINS_IDS = ALL_CHAINS.map((chain) => chain.id);

// src/chains/const/utils.ts
function mapSupportedNetworks(value) {
  return ALL_SUPPORTED_CHAIN_IDS.reduce(
    (acc, chainId) => ({
      ...acc,
      [chainId]: typeof value === "function" ? value(chainId) : value
    }),
    {}
  );
}
function mapAllNetworks(value) {
  return ALL_CHAINS_IDS.reduce(
    (acc, chainId) => ({
      ...acc,
      [chainId]: typeof value === "function" ? value(chainId) : value
    }),
    {}
  );
}
function mapAddressToSupportedNetworks(address) {
  return mapSupportedNetworks(address);
}

